import React from "react";
import Container from 'react-bootstrap/Container';
import "../styles/contact.css";
import "../index.css";
import Header from "../components/Header.js"
import Footer from "../components/Footer.js"
import ReactContactForm from 'react-mail-form';
import Card from 'react-bootstrap/Card';
import {Row, Col} from 'react-bootstrap';
import { FaCodeBranch } from "react-icons/fa";
import { SocialIcon } from 'react-social-icons';

class Contact extends React.Component {
    render() {
        return (
            <div id="contact" className="page">
                <Header />
                <Container style={{width:"100%", marginTop: "50px", marginBottom: "50px"}}>
                        <h1>Contact Me</h1>
                </Container>
                <Container style={{width:"100%", marginTop: "50px", marginBottom: "50px"}}>
                        <Row>
                        <div><img width="100%" src={require("../images/coder.png")} style={{marginBottom: "50px", display: "flex",  textAlign: "center"}}/></div>
                        <Col style={{width:"100%", marginTop: "100px"}}>
                            <h1>I'd love to talk! Please reach out to reid.anna.m@gmail.com with any inquiries!</h1>
                        </Col>
                        </Row>

                </Container>
                <Footer />
            </div>
        );
    }
}

export default Contact;
